1245   Function *F = I.getParent()->getParent();
1246   Value *ResultOp = I.getOperand(0);
1247 
1248   // If we are tracking the return value of this function, merge it in.
1249   if (!TrackedRetVals.empty() && !ResultOp->getType()->isStructTy()) {
1250     auto TFRVI = TrackedRetVals.find(F);
1251     if (TFRVI != TrackedRetVals.end()) {
1252       mergeInValue(TFRVI->second, F, getValueState(ResultOp));
1253       return;
1254     }
1255   }
1256 
1257   // Handle functions that return multiple values.
1258   if (!TrackedMultipleRetVals.empty()) {
1259     if (auto *STy = dyn_cast<StructType>(ResultOp->getType()))
1260       if (MRVFunctionsTracked.count(F))
1261         for (unsigned i = 0, e = STy->getNumElements(); i != e; ++i)
1262           mergeInValue(TrackedMultipleRetVals[std::make_pair(F, i)], F,
1263                        getStructValueState(ResultOp, i));
1264   }
